import{_ as t,o,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"29. Payment Of Wages","description":"","frontmatter":{"title":"29. Payment Of Wages","eba":"Biomedical Engineers 2025-2028","topics":["wages","preliminary","classifications"]},"headers":[],"relativePath":"ebas/biomedical-engineers/wages/29-payment-of-wages.md","filePath":"ebas/biomedical-engineers/wages/29-payment-of-wages.md"}'),r={name:"ebas/biomedical-engineers/wages/29-payment-of-wages.md"};function a(i,e,p,l,h,m){return o(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="_29-payment-of-wages" tabindex="-1">29. Payment Of Wages <a class="header-anchor" href="#_29-payment-of-wages" aria-label="Permalink to &quot;29. Payment Of Wages&quot;">​</a></h1><p><strong>29.1</strong> Frequency of payment Wages will be paid not later than Thursday following the end of the pay period, providing no unforeseen event outside the control of the Employer frustrates the Employer&#39;s ability to meet the requirements of this subclause.</p><p><strong>29.2</strong> Method of payment Wages will be paid by electronic funds transfer into the bank or financial institution account nominated by the Employee, unless otherwise agreed.</p><p><strong>29.3</strong> Payslip</p><p><strong>(a)</strong> On or prior to pay day, the Employer will provide each Employee with a pay slip.</p><p><strong>(b)</strong> The payslip will include the information required by the Act and Regulations, including but not limited to specifying:</p><p><strong>(i)</strong> the period to which the pay slip relates;</p><p><strong>(ii)</strong> the amount of wages to which the Employee is entitled;</p><p><strong>(iii)</strong> if an amount was deducted from the gross amount of the payment, the name and number of the fund or account into which the deduction was paid; and</p><p><strong>(iv)</strong> the net amount for each payment.</p><p><strong>29.4</strong> Records The Employer will comply with its obligations under the Act and Regulations with respect to record keeping, including but not limited to:</p><p><strong>(a)</strong> a requirement to keep a record that sets out any leave the Employee takes and the balance (if any) of the Employee&#39;s entitlement to that leave from time to time;</p><p><strong>(b)</strong> the inspection and copying of an Employee record by the Employee or former Employee to whom the record relates; and</p><p><strong>(c)</strong> the requirement to keep accurate Employee records.</p><p><strong>29.5</strong> Deductions</p><p>Any deductions from an Employee’s pay must be in accordance with section 324 of the Act.</p><p><strong>29.6</strong> Underpayments</p><p><strong>(a)</strong> Where an Employee considers they have been underpaid by reason of an error made by the Employer, the Employee may request that the Employer rectify the error.</p><p><strong>(b)</strong> Unless the Employee agrees to defer the correction of the underpayment, the underpayment will be corrected as follows:</p><p><strong>(i)</strong> if it is 5% or more of the Employee’s net fortnightly wage – where possible, by the end of the next business day;</p><p><strong>(ii)</strong> except in cases of hardship, if it is less than 5% of the Employee’s net fortnightly wage – in the next pay period;</p><p><strong>(iii)</strong> where the Employee notifies the Employer of hardship in respect of an amount owing less than 5% of the Employee’s net fortnightly wage - as soon as possible.</p><p><strong>(c)</strong> The Employer will notify the Employee of the adjustment being processed and provide the date of payment and any payment identification details.</p><p><strong>(d)</strong> This subclause 29.6 will not apply where:</p><p><strong>(i)</strong> the Employer and Employee are in genuine dispute as to whether the monies are owed to the Employee;</p><p><strong>(ii)</strong> the underpayment is the result of an Employee error which includes, but isn’t limited to, circumstances where the Employee hasn’t complied with the Employer’s policies dealing with the completion or approving of timesheets; or</p><p><strong>(iii)</strong> the reason for the underpayment is an unforeseen event or circumstance outside the control of the Employer, frustrating the Employer&#39;s ability to meet the requirements of this clause.</p>',27)])])}const c=t(r,[["render",a]]);export{g as __pageData,c as default};
